// This node collects status counts from multiple Gmail label queries.
// In a real implementation, you'd make parallel Gmail API calls.
// For now, this returns the template for the morning brief.

const brief = {
  date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/New_York' }),
  sections: [
    'Check Gmail labels for: AMANDA/STATE/PROCESSING, AMANDA/STATE/PROCESSED, AMANDA/QUEUE/*',
    'Check JR inbox unread count',
    'Check for any HITL timeout alerts pending',
  ],
};

return [{ json: brief }];

const date = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'America/New_York'
});

// Aggregate counts from previous nodes
const processingCount = $('Get Processing Items').all().length || 0;

const brief = [
  '☀️ AMANDA MORNING BRIEF',
  date,
  '',
  '📊 System Status:',
  `• In Processing: ${processingCount}`,
  '',
  '---',
  'Amanda Agent Core — OpenClaw n8n v1.0',
].join('\n');

return [{ json: { briefText: brief } }];
